// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : '';
const expectedKey = $env.OLLAMA_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  if (a.length > MAX_LEN || b.length > MAX_LEN) return false;

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length difference in constant-time comparison using XOR
  // XOR leaks length difference but doesn't create early return
  const lenDiff = a.length ^ b.length;
  result |= lenDiff;
  return result === 0;
}

if (expectedKey && !timingSafeEqual(providedKey, expectedKey)) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const message = input.message || '';
const model = input.model || 'llama3.2';
const systemPrompt = input.system || '';
const temperature = input.temperature;
const maxTokens = input.max_tokens;

// === MODEL VALIDATION ===
const validModelPattern = /^[a-zA-Z0-9._:-]+$/;
if (!validModelPattern.test(model)) {
  throw new Error('Invalid model name: must be alphanumeric, dot, dash, colon, or underscore only');
}
if (model.length > 100) {
  throw new Error('Model name too long: max 100 characters');
}

// === MESSAGE LENGTH VALIDATION ===
if (typeof message !== 'string') {
  throw new Error('Invalid message: must be a string');
}
if (message.length > 32768) {
  throw new Error('Message too long: max 32768 characters');
}
if (message.length === 0) {
  throw new Error('Missing required field: message');
}

// === SYSTEM PROMPT VALIDATION ===
if (typeof systemPrompt !== 'string') {
  throw new Error('Invalid system: must be a string');
}
if (systemPrompt.length > 8192) {
  throw new Error('System prompt too long: max 8192 characters');
}

// === TEMPERATURE VALIDATION ===
const tempValue = temperature !== undefined ? parseFloat(temperature) : 0.7;
if (isNaN(tempValue) || tempValue < 0.0 || tempValue > 2.0) {
  throw new Error('Invalid temperature: must be a number between 0.0 and 2.0');
}

// === MAX TOKENS VALIDATION ===
const tokensValue = maxTokens !== undefined ? parseInt(maxTokens, 10) : 2048;
if (isNaN(tokensValue) || tokensValue < 100 || tokensValue > 8192) {
  throw new Error('Invalid max_tokens: must be an integer between 100 and 8192');
}

// === CHANNEL VALIDATION ===
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  throw new Error('Invalid channel: must be alphanumeric, dash, or underscore only');
}

// Build messages array
const messages = [];
if (systemPrompt.trim()) {
  messages.push({ role: 'system', content: systemPrompt });
}
messages.push({ role: 'user', content: message });

return [{
  json: {
    model: model,
    messages: messages,
    temperature: tempValue,
    max_tokens: tokensValue,
    stream: false,
    channel: channelRaw
  }
}];

// Process Ollama response
const body = $input.first().json || {};
const webhookInput = $input.all()[1]?.json || {};

const message = body.message?.content || '';
const model = body.model || webhookInput.model || 'unknown';
const done = body.done || false;
const evalCount = body.eval_count || 0;
const promptEvalCount = body.prompt_eval_count || 0;
const totalDuration = body.total_duration || 0;

// Convert nanoseconds to seconds for readability
const durationSec = (totalDuration / 1e9).toFixed(2);

return [{
  json: {
    success: done && !!message,
    model: model,
    response: message,
    tokens_used: evalCount + promptEvalCount,
    prompt_tokens: promptEvalCount,
    completion_tokens: evalCount,
    duration_seconds: durationSec,
    timestamp: new Date().toISOString(),
    channel: webhookInput.channel || 'general'
  }
}];

